INSERT INTO "ecos_business_glossary" ("id", "term", "definition", "aliases", "domain", "status", "steward", "related_terms", "created_at", "updated_at") VALUES ('gl-001', '供应商', '向企业提供商品或服务的外部组织，包含供应商基本信息、资质证书、供应能力等', '供方,vendor,supplier', 'Procurement', 'Approved', '张三', 'gl-002,gl-003', '2026-06-14T23:39:10.489613', '2026-06-14T23:39:10.489613');
INSERT INTO "ecos_business_glossary" ("id", "term", "definition", "aliases", "domain", "status", "steward", "related_terms", "created_at", "updated_at") VALUES ('gl-002', '注册资本', '企业在工商行政管理机关登记的资本总额，反映企业规模和实力的重要指标', 'registered_capital,capital', 'Procurement', 'Approved', '张三', 'gl-001,gl-008', '2026-06-14T23:39:10.489613', '2026-06-14T23:39:10.489613');
INSERT INTO "ecos_business_glossary" ("id", "term", "definition", "aliases", "domain", "status", "steward", "related_terms", "created_at", "updated_at") VALUES ('gl-003', '统一社会信用代码', '由18位数字和字母组成的法人唯一身份标识，相当于企业的"身份证号"', '信用代码,USCC,credit_code', 'Procurement', 'Approved', '李四', 'gl-001', '2026-06-14T23:39:10.489613', '2026-06-14T23:39:10.489613');
INSERT INTO "ecos_business_glossary" ("id", "term", "definition", "aliases", "domain", "status", "steward", "related_terms", "created_at", "updated_at") VALUES ('gl-004', '客户', '购买企业产品或服务的组织或个人，是企业的收入来源', '甲方,customer,client', 'Sales', 'Approved', '王五', 'gl-005,gl-006', '2026-06-14T23:39:10.489613', '2026-06-14T23:39:10.489613');
INSERT INTO "ecos_business_glossary" ("id", "term", "definition", "aliases", "domain", "status", "steward", "related_terms", "created_at", "updated_at") VALUES ('gl-005', '合同金额', '合同中约定的交易总金额，包含税率和优惠折扣后的最终价格', '金额,amount,contract_value', 'Sales', 'Approved', '王五', 'gl-004,gl-006', '2026-06-14T23:39:10.489613', '2026-06-14T23:39:10.489613');
