INSERT INTO "ecos_decision_case" ("id", "title", "scenario", "tags", "decision", "result", "feedback", "source", "created_by", "created_at", "updated_at") VALUES (1, '数据质量提升对通行效率的影响', '当数据质量从60%提升至90%时，通行效率提升15%', '[''数据质量'', ''通行效率'', ''交通安全'']', '{''action'': ''提升数据采集频率'', ''params'': {''frequency'': ''5min''}}', '{''cost_change'': -0.02, ''efficiency_gain'': 0.15}', 'positive', 'causal', NULL, '2026-06-25T12:46:27.315171', '2026-06-25T12:46:27.315171');
