INSERT INTO "ecos_decision_case" ("id", "title", "scenario", "tags", "decision", "result", "feedback", "source", "created_by", "created_at", "updated_at") VALUES (4, '智慧路网建设规划', '建设智慧路网后，拥堵指数下降25%，用户满意度提升10点', '[''智慧路网'', ''用户满意度'', ''拥堵治理'']', '{''action'': ''智慧路网基础设施升级'', ''params'': {''phase'': 2, ''budget_m'': 500}}', '{''congestion_drop'': 0.25, ''satisfaction_gain'': 10}', 'positive', 'causal', NULL, '2026-06-25T12:46:27.325171', '2026-06-25T12:46:27.325171');
